#define THREADS_PER_BLOCK 256

__kernel void kernel_compute_cost(
    const int num,
    const int dim,
    const long x,
    const Point_Struct *p,
    const int K,
    const int stride,
    const float *coord_d,
    float *work_mem_d,
    const int *center_table_d,
    char *switch_membership_d)
{
    const int tid = get_global_id(0);

    if(tid < num)
    {
        float *lower = &work_mem_d[tid*stride];

        float retval = 0.0f;
        for(int i = 0; i < dim; i++){
            float tmp = coord_d[(i*num)+tid] - coord_d[(i*num)+x];
            retval += tmp * tmp;
        }

        float x_cost = retval * p[tid].weight;

        if ( x_cost < p[tid].cost )
        {
            switch_membership_d[tid] = 1;
            lower[K] += x_cost - p[tid].cost;
        }
        else
        {
            lower[center_table_d[p[tid].assign]] += p[tid].cost - x_cost;
        }
    }
}
